// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-datos-vehiculo-by-patente

const input = $input.first().json;

// Extraer datos
let patente = input.patente;

// VALIDACIONES
const errores = [];

// 1. Verificar que patente existe y no es nulo/undefined
if (!patente || patente === null || patente === undefined) {
  errores.push("La patente es obligatoria y no puede ser nula");
}

// Si la patente existe, proceder con limpieza y validaciones
if (patente) {
  // 2. Convertir a string si no lo es
  patente = String(patente);

  // 3. Limpiar: quitar espacios, guiones y caracteres especiales
  patente = patente.trim()
                   .replace(/[-\s_./]/g, '')  // quita guiones, espacios, guiones bajos, puntos, barras
                   .toUpperCase();             // convierte a mayúsculas

  // 4. Verificar que no quedó vacía después de limpiar
  if (patente.length === 0) {
    errores.push("La patente no puede estar vacía después de limpiar");
  }

  // 5. Validar longitud (patentes argentinas pueden ser 6 o 7 caracteres)
  // Formato viejo: ABC123 (6 chars) - Formato nuevo: AB123CD (7 chars)
  if (patente.length < 6 || patente.length > 7) {
    errores.push(`La patente debe tener 6 o 7 caracteres (recibido: ${patente.length})`);
  }

  // 6. Validar que solo contenga letras y números
  const soloAlfanumerico = /^[A-Z0-9]+$/;
  if (!soloAlfanumerico.test(patente)) {
    errores.push("La patente solo puede contener letras y números");
  }

  // 7. Validación adicional de formato argentino (opcional, comentar si no aplica)
  const formatoViejo = /^[A-Z]{3}[0-9]{3}$/;  // ABC123
  const formatoNuevo = /^[A-Z]{2}[0-9]{3}[A-Z]{2}$/;  // AB123CD

  if (!formatoViejo.test(patente) && !formatoNuevo.test(patente)) {
    errores.push(`Formato de patente inválido. Debe ser ABC123 o AB123CD (recibido: ${patente})`);
  }
}

// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        patente_original: input.patente,
        patente_limpia: patente || null
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados
return [{
  json: {
    success: true,
    patente: patente,  // patente ya limpia y validada
    patente_original: input.patente  // guardar original por si acaso
  }
}];

// PROCESAR DATOS DE VEHÍCULO Y GENERAR RESPUESTA

// Datos de entrada
//const trigger = $('trigger-get-datos').first().json;
const httpResponse = $input.first().json;

// Patente solicitada (ya validada y limpia)
const patenteSolicitada = $('validar-formato').first().json.patente;

// Extraer vehículos desde la respuesta del CRM
const vehiculosEncontrados = httpResponse.InternalObject || [];

// Verificar si se encontraron vehículos
const vehiculoEncontrado = vehiculosEncontrados.length > 0;

// Procesar datos del vehículo (tomar el primero si hay múltiples)
let datosVehiculo = null;
let mensaje = "";

if (vehiculoEncontrado) {
  // Tomar el primer vehículo (o el más reciente por DOC_ID)
  const vehiculo = vehiculosEncontrados[0];

  datosVehiculo = {
    doc_id: vehiculo.DOC_ID || null,
    patente: vehiculo.VEHICULO || patenteSolicitada,
    marca: vehiculo.MARCA || null,
    modelo: vehiculo.MODELO || null,
    kms: vehiculo.KMS || null,
    telefono: vehiculo.TELEFONO || null,
    servicio: vehiculo.SERVICIO || null,
    fecha_ultima_visita: vehiculo.FECHA || null,
    hora_ultima_visita: vehiculo.HORA || null,
    titular: vehiculo.TITULAR || null,
    subject: vehiculo.SUBJECT || null
  };

  mensaje = `✅ Vehículo encontrado: ${datosVehiculo.marca} ${datosVehiculo.modelo} - Patente: ${datosVehiculo.patente}`;

} else {
  mensaje = `❌ No se encontró ningún vehículo con la patente: ${patenteSolicitada}`;
}

// Preparar respuesta estructurada
const respuesta = {
  success: true,
  patente_solicitada: patenteSolicitada,
  vehiculo_encontrado: vehiculoEncontrado,
  total_registros: vehiculosEncontrados.length,
  mensaje: mensaje,

  // Datos del vehículo (null si no se encontró)
  vehiculo: datosVehiculo,

  // Todos los registros encontrados (por si hay múltiples)
  todos_los_registros: vehiculosEncontrados.map(v => ({
    doc_id: v.DOC_ID,
    patente: v.VEHICULO,
    marca: v.MARCA,
    modelo: v.MODELO,
    kms: v.KMS,
    telefono: v.TELEFONO,
    servicio: v.SERVICIO,
    fecha: v.FECHA,
    hora: v.HORA,
    titular: v.TITULAR,
    subject: v.SUBJECT
  })),

  // Info adicional útil
  ultima_visita: datosVehiculo ? {
    fecha: datosVehiculo.fecha_ultima_visita,
    hora: datosVehiculo.hora_ultima_visita,
    servicio: datosVehiculo.servicio
  } : null,

  // Estadísticas
  tiene_historial: vehiculosEncontrados.length > 1,
  cantidad_visitas: vehiculosEncontrados.length
};

return [{ json: respuesta }];

// En el nodo "salida_con_error" (Code node)
const errores = $input.first().json.errores || ["Error de validación"];

return [{
  json: {
    success: false,
    error: "VALIDACION_FALLIDA",
    errores: errores,
    disponible: false,
    mensaje: errores.join(", ")
  }
}];
